def total_match(lst1, lst2):
    '''
    Write a function that accepts two lists of strings and returns the list that has 
    total number of chars in the all strings of the list less than the other list.

    if the two lists have the same number of chars, return the first list.

    Examples
    total_match([], []) ➞ []
    total_match(['hi', 'admin'], ['hI', 'Hi']) ➞ ['hI', 'Hi']
    total_match(['hi', 'admin'], ['hi', 'hi', 'admin', 'project']) ➞ ['hi', 'admin']
    total_match(['hi', 'admin'], ['hI', 'hi', 'hi']) ➞ ['hI', 'hi', 'hi']
    total_match(['4'], ['1', '2', '3', '4', '5']) ➞ ['4']
    '''

    # Check if both lists are equal and return one of the lists
    if lst1 == lst2:
        return lst1

    # Check if both lists are equal and return one of the lists
    if lst1 == []:
        return lst2

    # Check if both lists are equal and return one of the lists
    if lst2 == []:
        return lst1

    # Check if both lists contain the same chars
    lst1_chars = []
    lst2_chars = []

    for i in lst1:
        for c in i:
            lst1_chars.append(c)

    for i in lst2:
        for c in i:
            lst2_chars.append(c)

    # Check if both lists contain the same chars
    if lst1_chars == lst2_chars:
        return lst1

    # Check if one list contains all the chars from other list and return one of the lists
    for c in lst1_chars:
        if c not in lst2_chars:
            return lst1

    # Check if one list contains all the chars from other list and return one of the lists
    for c in lst2_chars:
        if c not in lst1_chars:
            return lst2

    # Return first list as default
    return lst1

